  double v = input;
  return math.asin(v);
}

double _mathAcos(double input) {
  double v = input;
  return math.acos(v);
}

double _mathAtan(double input) {
  double v = input;
  return math.atan(v);
}

double _mathAtan2(double a, double b) => math.atan2(a, b);
